parameters.functionCode:
const domains = ['example.com', 'api.example.com'];
const results = [];

for (const domain of domains) {
  try {
    // Use WHOIS API to check domain expiry
    const response = await this.helpers.httpRequest({
      url: `https://www.whoisxmlapi.com/whoisserver/WhoisService?domainName=${domain}&apiKey=YOUR_API_KEY`,
      method: 'GET',
      returnFullResponse: true
    });

    const data = JSON.parse(response.body);
    const expiryDate = new Date(data.WhoisRecord.expiresDate);
    const daysUntilExpiry = Math.floor((expiryDate - new Date()) / (1000 * 60 * 60 * 24));

    results.push({
      domain: domain,
      expiryDate: expiryDate.toISOString(),
      daysUntilExpiry: daysUntilExpiry,
      registrar: data.WhoisRecord.registrarName || 'Unknown',
      needsAlert: daysUntilExpiry <= 30
    });
  } catch (error) {
    results.push({
      domain: domain,
      error: error.message,
      needsAlert: true
    });
  }
}

return results.map(item => ({ json: item }));

